(1, 'samsung-galaxy-s25-ultra-review', 'Samsung Galaxy S25 Ultra Review: The Android King Returns', 'The S25 Ultra sets a new bar for Android flagships with its Snapdragon 8 Elite chip and refined S Pen experience.', NULL, 'review', 'Editorial Team', NULL, 1, 0, 'Samsung', '2026-03-16 16:46:07'),
(2, 'iphone-16-pro-max-six-months-later', 'iPhone 16 Pro Max: Six Months Later', 'After half a year of daily use, here is what we really think about Apple latest flagship and whether it is still worth buying.', NULL, 'review', 'Editorial Team', NULL, 0, 0, 'Apple', '2026-03-16 16:46:07'),
(3, 'best-phones-under-500-2026', 'Best Phones Under $500 in 2026', 'We tested 20 mid-range phones to find the best value champions. The results may surprise you.', NULL, 'deep-dive', 'Editorial Team', NULL, 1, 0, NULL, '2026-03-16 16:46:07'),
(4, 'snapdragon-8-elite-vs-dimensity-9400', 'Snapdragon 8 Elite vs Dimensity 9400: Which Chip Wins?', 'A comprehensive deep dive into the two most powerful mobile chipsets of 2025 and what they mean for real-world performance.', NULL, 'comparison', 'Editorial Team', NULL, 0, 0, NULL, '2026-03-16 16:46:07'),
(5, 'xiaomi-15-ultra-camera-test', 'Xiaomi 15 Ultra Camera Deep Dive: Leica Magic Explained', 'We put the Xiaomi 15 Ultra camera system through its paces in every lighting condition imaginable.', NULL, 'review', 'Editorial Team', NULL, 0, 0, 'Xiaomi', '2026-03-16 16:46:07'),
(6, 'upcoming-flagships-2026-preview', 'Every Major Flagship Coming in 2026', 'From Samsung Galaxy S26 to iPhone 17, here is everything we know about the most anticipated phones of the year.', NULL, 'news', 'Editorial Team', NULL, 1, 0, NULL, '2026-03-16 16:46:07');
